namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
        new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
        new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
        new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
        new() { Id = 5, Name = "Biology", Code = "BIO", Description = "Study of living organisms and life processes." },
    ];

    private readonly List<Course> _courses =
    [
        new() { Id = 1, DepartmentId = 1, Code = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses. Her research focuses on CS education and pedagogy.", IsFeatured = true },
        new() { Id = 2, DepartmentId = 1, Code = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Rivera", InstructorBio = "Dr. Rivera specializes in algorithm optimization and has published extensively on graph algorithms.", IsFeatured = true },
        new() { Id = 3, DepartmentId = 1, Code = "CS 301", Title = "Software Engineering", Description = "Principles of software development including requirements, design patterns, testing, and project management.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Prof. Maria Lopez", InstructorBio = "Prof. Lopez spent 10 years in industry at major tech companies before joining academia." },
        new() { Id = 4, DepartmentId = 2, Code = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Kim", InstructorBio = "Dr. Kim is an award-winning educator known for making calculus accessible to all students.", IsFeatured = true },
        new() { Id = 5, DepartmentId = 2, Code = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science and machine learning.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Emily Park", InstructorBio = "Dr. Park's research spans applied mathematics and computational methods." },
        new() { Id = 6, DepartmentId = 3, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is an experimental physicist with a passion for hands-on learning." },
        new() { Id = 7, DepartmentId = 3, Code = "PHYS 201", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Lisa Nguyen", InstructorBio = "Dr. Nguyen's research focuses on quantum electrodynamics and photonics.", IsFeatured = true },
        new() { Id = 8, DepartmentId = 4, Code = "ENG 101", Title = "Composition & Rhetoric", Description = "Develop skills in academic writing, argumentation, and critical analysis of texts.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Prof. David Wright", InstructorBio = "Prof. Wright is a published author and expert in rhetorical theory." },
        new() { Id = 9, DepartmentId = 4, Code = "ENG 220", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Dr. Angela Brooks", InstructorBio = "Dr. Brooks specializes in 20th-century American fiction and has authored three books on the subject." },
        new() { Id = 10, DepartmentId = 5, Code = "BIO 101", Title = "General Biology", Description = "Introduction to cell biology, genetics, evolution, and ecology. Includes weekly lab.", Credits = 4, Schedule = "Mon/Wed 9:00–10:20 AM + Lab Fri 1:00–3:50 PM", InstructorName = "Dr. Karen Mitchell", InstructorBio = "Dr. Mitchell is a molecular biologist whose research explores gene expression in plants.", IsFeatured = true },
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> SearchCourses(string? query, int? departmentId)
    {
        var results = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            results = results.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(query))
        {
            var q = query.Trim().ToLowerInvariant();
            results = results.Where(c =>
                c.Title.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(q, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0;
    }
}

