@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="/courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="query" value="@Query" class="form-control" placeholder="Search by title, code, or keyword..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in Catalog.GetDepartments())
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Code &mdash; @dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td>@course.Schedule</td>
                    <td><a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Query { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = [];

    protected override void OnInitialized()
    {
        courses = Catalog.SearchCourses(Query, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="/courses">Back to course list</a>
}
else
{
    <PageTitle>@course.Code - @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/courses?departmentId=@course.DepartmentId">@department?.Name</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code &mdash; @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h3>Description</h3>
            <p>@course.Description</p>

            <h3>Instructor</h3>
            <p><strong>@course.InstructorName</strong></p>
            <p>@course.InstructorBio</p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Course Details</h5>
                    <ul class="list-unstyled">
                        <li><strong>Credits:</strong> @course.Credits</li>
                        <li><strong>Schedule:</strong> @course.Schedule</li>
